import{_ as t,o as e,c as n,a2 as d}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"工程实践","description":"","frontmatter":{},"headers":[],"relativePath":"practice/index.md","filePath":"practice/index.md","lastUpdated":null}'),i={name:"practice/index.md"};function s(r,a,l,o,p,c){return e(),n("div",null,[...a[0]||(a[0]=[d(`<h1 id="工程实践" tabindex="-1">工程实践 <a class="header-anchor" href="#工程实践" aria-label="Permalink to &quot;工程实践&quot;">​</a></h1><blockquote><p>本栏目内容不来自《Spring 技术套件》原文档，是为补齐「Java 后端全技术」而新增的工程实践部分。</p></blockquote><p>掌握了语言、框架和中间件之后，真正决定项目质量的往往是这些&quot;看不见&quot;的工程能力：构建怎么管、代码怎么组织、SQL 怎么写好、接口怎么定规范。这一层不引入新组件，而是讲清楚如何把已有技术用好。</p><h2 id="本栏目内容" tabindex="-1">本栏目内容 <a class="header-anchor" href="#本栏目内容" aria-label="Permalink to &quot;本栏目内容&quot;">​</a></h2><ul><li><a href="./maven">Maven 与依赖管理</a>：多模块、依赖仲裁、BOM、profile 与常用插件。</li><li><a href="./design-pattern">设计模式与架构</a>：常用设计模式、分层架构、DDD 与整洁架构思想。</li><li><a href="./sql-optimization">SQL 优化与索引</a>：索引原理、执行计划、事务隔离与慢查询排查。</li><li><a href="./api-design">API 设计规范</a>：RESTful 风格、统一返回、全局异常、幂等与分页。</li></ul><h2 id="为什么单独成栏" tabindex="-1">为什么单独成栏 <a class="header-anchor" href="#为什么单独成栏" aria-label="Permalink to &quot;为什么单独成栏&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>现象</th><th>这一层解决什么</th></tr></thead><tbody><tr><td>依赖混乱</td><td>版本冲突、jar 包冲突、打包失败</td><td>用 Maven BOM 和依赖仲裁统一管理</td></tr><tr><td>代码难维护</td><td>改一处崩一片、逻辑散落各处</td><td>用设计模式和分层架构约束结构</td></tr><tr><td>数据库慢</td><td>接口越来越慢、CPU 飙高</td><td>用索引和 SQL 优化解决根因</td></tr><tr><td>接口不统一</td><td>每个人返回格式不同、前端难对接</td><td>用统一规范约定返回、异常、分页</td></tr></tbody></table><h2 id="实践原则" tabindex="-1">实践原则 <a class="header-anchor" href="#实践原则" aria-label="Permalink to &quot;实践原则&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先让代码能跑</span></span>
<span class="line"><span>再让代码可读</span></span>
<span class="line"><span>再让代码可测</span></span>
<span class="line"><span>最后才追求可扩展</span></span></code></pre></div><p>不要一上来就套用复杂的设计模式或 DDD，过度设计和不设计同样有害。规范的价值在于团队协作时减少沟通成本，规模越大收益越明显。</p>`,10)])])}const _=t(i,[["render",s]]);export{u as __pageData,_ as default};
